import axios from 'axios';
import React, { useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useGetAllProductsQuery } from './MyorderApi';

const MyOrder = () => {
  const [orderData, setorderData] = useState();
  var userid= sessionStorage.getItem("UserInfoID")
  const [todos, setTodos] = useState([]);


  useEffect(()=>{
    getAllData()
    alert("fsdfsdf")
  })

  

  const getAllData=()=>{
    axios.get(`http://localhost:1313/myorder/${userid}`).then((res)=>{
      //  const allData = res.data.orderData.allData;
      //  console.log(r)
       console.log(res)
      //  setorderData(allData)
    }).catch(error =>{
      console.log("Error",error)
    })
  }


  return (
    <div>
     <table className="table mt-5 text-conter">
        <thead>
          <tr>
            <th>descripiton</th>
            <th>Edit</th>
            <th>Delete</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td></td>
          </tr>
          {todos.map((todo) => (
            <tr key={todo.todo_id}>
              <td>{todo.description}</td>
              <td><EditTodo todo={todo} /></td>
              <td>
                {" "}
                <button
                  className="btn btn-danger"
                  onClick={() => deleteTodo(todo.todo_id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

export default MyOrder
